from dataclasses import dataclass

@dataclass
class GroundednessResult:
    nli_score: float           # 0-1, from SummaC
    qa_score: float            # 0-1, fraction of QA pairs grounded
    llm_score: int             # 1-5, from judge
    overall: str               # 'grounded' | 'partial' | 'not_grounded'
    flags: list[str]

def composite_groundedness(
    context: str,
    response: str,
    use_llm_judge: bool = True,
) -> GroundednessResult:
    nli = summac_score(context, response)          # from earlier
    qa = qa_faithfulness(context, response)['score']  # from earlier
    llm = judge_groundedness(context, response)['score'] if use_llm_judge else None

    flags = []
    if nli < 0.5:
        flags.append(f'NLI contradiction detected (score={nli:.2f})')
    if qa < 0.6:
        flags.append(f'QA faithfulness low (score={qa:.2f})')
    if llm is not None and llm <= 2:
        flags.append(f'LLM judge rated poorly (score={llm}/5)')

    # Aggregate
    weak_signals = sum([nli < 0.5, qa < 0.6, (llm or 3) <= 2])
    if weak_signals == 0:
        overall = 'grounded'
    elif weak_signals == 1:
        overall = 'partial'
    else:
        overall = 'not_grounded'

    return GroundednessResult(
        nli_score=nli,
        qa_score=qa,
        llm_score=llm or 0,
        overall=overall,
        flags=flags,
    )
